import React, { useState, useEffect, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
    cyan: '#22d3ee',
  },
  font: "'JetBrains Mono', monospace",
};

const expertColors = ['#38bdf8', '#fbbf24', '#f472b6', '#a3e635'];
const expertColorsDim = ['#38bdf820', '#fbbf2420', '#f472b620', '#a3e63520'];

function softmax(logits) {
  const max = Math.max(...logits);
  const exps = logits.map(x => Math.exp(x - max));
  const sum = exps.reduce((a, b) => a + b, 0);
  return exps.map(e => e / sum);
}

function getTopK(probs, k) {
  const indexed = probs.map((v, i) => ({ value: v, index: i }));
  indexed.sort((a, b) => b.value - a.value);
  const selected = indexed.slice(0, k);
  const sumW = selected.reduce((s, t) => s + t.value, 0);
  return selected.map(s => ({
    expertIdx: s.index,
    rawWeight: s.value,
    normWeight: s.value / sumW,
  }));
}

const TOKENS = ['The', 'cat', 'sat', 'down'];
const NUM_EXPERTS = 4;

const GATING_LOGITS = [
  [2.5, 1.8, 0.1, 0.3],
  [0.2, 2.8, 1.6, 0.1],
  [0.8, 0.1, 2.3, 1.9],
  [0.4, 0.6, 0.9, 2.7],
];

const STEPS = [
  { title: 'Explore Routing', desc: 'Change k to see how many experts each token uses. Click tokens to inspect.', color: theme.colors.primary },
  { title: 'Step 1: Gating Scores', desc: 'Softmax converts raw logits into probability weights over all experts.', color: theme.colors.blue },
  { title: 'Step 2: Top-k Selection', desc: 'Only the k highest-weight experts are kept. The rest are zeroed out (sparsity!).', color: theme.colors.yellow },
  { title: 'Step 3: Renormalize & Aggregate', desc: 'Selected weights are renormalized to sum to 1, then used to weight expert outputs.', color: theme.colors.green },
];

export default function App() {
  const [k, setK] = useState(2);
  const [selToken, setSelToken] = useState(0);
  const [step, setStep] = useState(0);
  const [playing, setPlaying] = useState(false);

  const allProbs = useMemo(() => GATING_LOGITS.map(l => softmax(l)), []);
  const allRoutings = useMemo(() => allProbs.map(p => getTopK(p, k)), [allProbs, k]);

  useEffect(() => {
    if (!playing) return;
    const timer = setInterval(() => {
      setStep(prev => {
        if (prev >= 3) { setPlaying(false); return 3; }
        return prev + 1;
      });
    }, 2000);
    return () => clearInterval(timer);
  }, [playing]);

  const svgW = 560;
  const svgH = 240;
  const tokenX = 12;
  const tokenW = 52;
  const tokenH = 34;
  const expertX = svgW - 64;
  const expertW = 52;
  const expertH = 34;
  const yStart = 30;
  const ySpacing = 54;

  const tokenYs = TOKENS.map((_, i) => yStart + i * ySpacing);
  const expertYs = Array.from({ length: NUM_EXPERTS }, (_, i) => yStart + i * ySpacing);

  const routes = useMemo(() => {
    const result = [];
    for (let ti = 0; ti < TOKENS.length; ti++) {
      const routing = allRoutings[ti];
      const selectedSet = new Set(routing.map(r => r.expertIdx));
      for (let ei = 0; ei < NUM_EXPERTS; ei++) {
        const prob = allProbs[ti][ei];
        const isSelected = selectedSet.has(ei);
        const routeInfo = routing.find(r => r.expertIdx === ei);
        result.push({
          tokenIdx: ti,
          expertIdx: ei,
          prob,
          isSelected,
          normWeight: routeInfo ? routeInfo.normWeight : 0,
          x1: tokenX + tokenW,
          y1: tokenYs[ti] + tokenH / 2,
          x2: expertX,
          y2: expertYs[ei] + expertH / 2,
        });
      }
    }
    return result;
  }, [allRoutings, allProbs, tokenYs, expertYs]);

  const selProbs = allProbs[selToken];
  const selRouting = allRoutings[selToken];
  const selSet = new Set(selRouting.map(r => r.expertIdx));

  const activeExperts = useMemo(() => {
    const counts = Array(NUM_EXPERTS).fill(0);
    allRoutings.forEach(r => r.forEach(ri => { counts[ri.expertIdx]++; }));
    return counts;
  }, [allRoutings]);

  const totalRoutes = TOKENS.length * k;

  function getInsight() {
    if (k === 1) return 'With k=1, each token uses only its single best expert. Maximum sparsity, minimum computation, but limited expressivity.';
    if (k === 2) return 'With k=2, tokens blend two experts. Good balance of sparsity and expressivity - the most common setting in practice.';
    if (k === 3) return 'With k=3, most experts are active per token. Less sparse, more computation, but captures richer representations.';
    return 'With k=4 (all experts), this is a dense MoE - no sparsity. Every expert contributes to every token. Equivalent to an ensemble.';
  }

  return (
    <div style={{ background: theme.colors.background, minHeight: '100vh', display: 'flex', justifyContent: 'center', alignItems: 'flex-start', padding: '16px 12px', fontFamily: theme.font, color: theme.colors.text, boxSizing: 'border-box' }}>
      <div style={{ width: '100%', maxWidth: 600, display: 'flex', flexDirection: 'column', gap: 8 }}>

        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <div style={{ fontSize: 18, fontWeight: 700 }}>Sparse Mixture of Experts</div>
            <div style={{ fontSize: 11, color: theme.colors.textMuted, marginTop: 2 }}>Route tokens to top-k experts, aggregate weighted outputs</div>
          </div>
          <div style={{ display: 'flex', gap: 6 }}>
            <button onClick={() => { if (!playing) { setStep(0); setPlaying(true); } else { setPlaying(false); } }} style={{ padding: '6px 14px', background: playing ? theme.colors.surfaceAlt : theme.colors.primary, border: 'none', borderRadius: 6, color: theme.colors.text, fontFamily: theme.font, fontSize: 13, cursor: 'pointer' }}>
              {playing ? 'Pause' : 'Play'}
            </button>
            <button onClick={() => { setStep(0); setPlaying(false); setK(2); setSelToken(0); }} style={{ padding: '6px 10px', background: theme.colors.surface, border: 'none', borderRadius: 6, color: theme.colors.text, fontFamily: theme.font, fontSize: 13, cursor: 'pointer' }}>~</button>
          </div>
        </div>

        {/* Step Info */}
        <div style={{ padding: '8px 12px', background: STEPS[step].color + '15', border: '1px solid ' + STEPS[step].color + '40', borderRadius: 8, fontSize: 11, color: theme.colors.textSecondary, lineHeight: 1.5 }}>
          <strong style={{ color: STEPS[step].color }}>{STEPS[step].title}</strong>{' -- '}{STEPS[step].desc}
        </div>

        {/* K Selector */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '4px 0' }}>
          <span style={{ fontSize: 12, color: theme.colors.textSecondary }}>top-k =</span>
          {[1, 2, 3, 4].map(v => (
            <button key={v} onClick={() => setK(v)} style={{ width: 36, height: 32, borderRadius: 6, border: v === k ? '2px solid ' + theme.colors.primary : '1px solid ' + theme.colors.border, background: v === k ? theme.colors.primary + '30' : theme.colors.surface, color: v === k ? theme.colors.primary : theme.colors.textMuted, fontFamily: theme.font, fontSize: 14, fontWeight: 700, cursor: 'pointer', transition: 'all 0.2s ease' }}>{v}</button>
          ))}
          <span style={{ fontSize: 10, color: theme.colors.textMuted, marginLeft: 8 }}>{totalRoutes} routes active ({k === NUM_EXPERTS ? 'dense' : Math.round((1 - k / NUM_EXPERTS) * 100) + '% sparse'})</span>
        </div>

        {/* Main SVG */}
        <div style={{ background: theme.colors.surface, borderRadius: 10, border: '1px solid ' + theme.colors.border, padding: '8px 4px', overflow: 'hidden' }}>
          <svg viewBox={'0 0 ' + svgW + ' ' + svgH} width="100%" style={{ display: 'block' }}>
            <defs>
              {expertColors.map((c, i) => (
                <linearGradient key={'g' + i} id={'grad' + i} x1="0%" y1="0%" x2="100%" y2="0%">
                  <stop offset="0%" stopColor={c} stopOpacity="0.8" />
                  <stop offset="100%" stopColor={c} stopOpacity="0.4" />
                </linearGradient>
              ))}
            </defs>

            {/* Connection lines */}
            {routes.map((r, idx) => {
              const isActive = r.isSelected;
              const isSelTokenRoute = r.tokenIdx === selToken;
              const showLine = step === 0 ? isActive : step === 1 ? true : isActive;
              const lineOpacity = step === 1 ? (isActive ? 0.5 : 0.12) : (isActive ? (isSelTokenRoute ? 0.9 : 0.55) : 0);
              const sw = isActive ? Math.max(1.5, r.normWeight * 5) : 0.5;
              const cpOff = 140;
              const d = 'M' + r.x1 + ',' + r.y1 + ' C' + (r.x1 + cpOff) + ',' + r.y1 + ' ' + (r.x2 - cpOff) + ',' + r.y2 + ' ' + r.x2 + ',' + r.y2;
              return (
                <path key={idx} d={d}
                  fill="none"
                  stroke={expertColors[r.expertIdx]}
                  strokeWidth={sw}
                  opacity={lineOpacity}
                  strokeDasharray={(!isActive && step === 1) ? '3,3' : 'none'}
                  style={{ transition: 'all 0.4s ease' }}
                />
              );
            })}

            {/* Weight labels on active routes for selected token */}
            {selRouting.map((r) => {
              const tY = tokenYs[selToken] + tokenH / 2;
              const eY = expertYs[r.expertIdx] + expertH / 2;
              const midX = svgW / 2;
              const midY = (tY + eY) / 2 - 6;
              const label = step >= 3 ? r.normWeight.toFixed(2) : r.rawWeight.toFixed(2);
              return (
                <text key={'wl' + r.expertIdx} x={midX} y={midY}
                  fill={expertColors[r.expertIdx]}
                  fontSize={9} fontFamily={theme.font}
                  textAnchor="middle"
                  opacity={0.9}
                  style={{ transition: 'all 0.3s ease' }}
                >
                  {step >= 3 ? 'w=' + label : 'p=' + label}
                </text>
              );
            })}

            {/* Tokens */}
            {TOKENS.map((tok, i) => {
              const isSel = i === selToken;
              return (
                <g key={'t' + i} onClick={() => setSelToken(i)} style={{ cursor: 'pointer' }}>
                  <rect x={tokenX} y={tokenYs[i]} width={tokenW} height={tokenH} rx={6}
                    fill={isSel ? theme.colors.primary + '30' : theme.colors.surfaceAlt}
                    stroke={isSel ? theme.colors.primary : theme.colors.border}
                    strokeWidth={isSel ? 2 : 1}
                    style={{ transition: 'all 0.2s ease' }}
                  />
                  <text x={tokenX + tokenW / 2} y={tokenYs[i] + tokenH / 2 + 1}
                    fill={isSel ? theme.colors.text : theme.colors.textSecondary}
                    fontSize={12} fontFamily={theme.font} textAnchor="middle" dominantBaseline="middle"
                    fontWeight={isSel ? 700 : 400}
                  >{tok}</text>
                </g>
              );
            })}

            {/* Label: Tokens */}
            <text x={tokenX + tokenW / 2} y={14} fill={theme.colors.textMuted} fontSize={9} fontFamily={theme.font} textAnchor="middle">TOKENS</text>

            {/* Experts */}
            {Array.from({ length: NUM_EXPERTS }, (_, i) => {
              const active = activeExperts[i] > 0;
              return (
                <g key={'e' + i}>
                  <rect x={expertX} y={expertYs[i]} width={expertW} height={expertH} rx={6}
                    fill={active ? expertColors[i] + '20' : theme.colors.surfaceAlt}
                    stroke={active ? expertColors[i] + '80' : theme.colors.border}
                    strokeWidth={active ? 1.5 : 1}
                    style={{ transition: 'all 0.3s ease' }}
                  />
                  <text x={expertX + expertW / 2} y={expertYs[i] + tokenH / 2 + 1}
                    fill={active ? expertColors[i] : theme.colors.textMuted}
                    fontSize={11} fontFamily={theme.font} textAnchor="middle" dominantBaseline="middle"
                    fontWeight={active ? 600 : 400}
                  >E{i}</text>
                  {/* Usage count badge */}
                  <circle cx={expertX + expertW + 10} cy={expertYs[i] + tokenH / 2} r={8}
                    fill={active ? expertColors[i] + '30' : 'transparent'}
                    style={{ transition: 'all 0.3s ease' }}
                  />
                  <text x={expertX + expertW + 10} y={expertYs[i] + tokenH / 2 + 1}
                    fill={active ? expertColors[i] : 'transparent'}
                    fontSize={8} fontFamily={theme.font} textAnchor="middle" dominantBaseline="middle"
                  >{activeExperts[i]}</text>
                </g>
              );
            })}

            {/* Label: Experts */}
            <text x={expertX + expertW / 2} y={14} fill={theme.colors.textMuted} fontSize={9} fontFamily={theme.font} textAnchor="middle">EXPERTS</text>

            {/* Center label */}
            <text x={svgW / 2} y={svgH - 6} fill={theme.colors.textMuted} fontSize={9} fontFamily={theme.font} textAnchor="middle">
              {step >= 3 ? 'Normalized weights (sum to 1)' : step >= 2 ? 'Top-' + k + ' routes selected' : step >= 1 ? 'All gating probabilities' : 'Click a token to inspect routing'}
            </text>
          </svg>
        </div>

        {/* Detail Panel */}
        <div style={{ background: theme.colors.surface, borderRadius: 8, border: '1px solid ' + theme.colors.border, padding: '10px 14px' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
            <div style={{ fontSize: 11, color: theme.colors.textMuted }}>TOKEN <span style={{ color: theme.colors.primary, fontWeight: 700 }}>"{TOKENS[selToken]}"</span> GATING</div>
            <div style={{ fontSize: 9, color: theme.colors.textMuted }}>logits: [{GATING_LOGITS[selToken].map(l => l.toFixed(1)).join(', ')}]</div>
          </div>

          {/* Probability bars */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
            {selProbs.map((p, i) => {
              const isTop = selSet.has(i);
              const routeInfo = selRouting.find(r => r.expertIdx === i);
              return (
                <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                  <span style={{ fontSize: 10, color: expertColors[i], width: 20, textAlign: 'right', fontWeight: 600 }}>E{i}</span>
                  <div style={{ flex: 1, height: 16, background: theme.colors.surfaceAlt, borderRadius: 4, position: 'relative', overflow: 'hidden' }}>
                    <div style={{
                      height: '100%',
                      width: (p * 100) + '%',
                      background: isTop ? expertColors[i] + '60' : expertColors[i] + '15',
                      borderRadius: 4,
                      border: isTop ? '1px solid ' + expertColors[i] : '1px solid transparent',
                      transition: 'all 0.3s ease',
                    }} />
                  </div>
                  <span style={{ fontSize: 10, color: isTop ? theme.colors.text : theme.colors.textMuted, width: 34, fontWeight: isTop ? 600 : 400, transition: 'all 0.3s ease' }}>{p.toFixed(2)}</span>
                  {step >= 3 && isTop && routeInfo ? (
                    <span style={{ fontSize: 9, color: theme.colors.green, width: 50 }}>-> {routeInfo.normWeight.toFixed(2)}</span>
                  ) : (
                    <span style={{ width: 50, fontSize: 9, color: isTop ? theme.colors.yellow : 'transparent' }}>{isTop ? 'top-' + k : ''}</span>
                  )}
                </div>
              );
            })}
          </div>

          {/* Routing summary */}
          <div style={{ marginTop: 8, display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap' }}>
            <span style={{ fontSize: 10, color: theme.colors.textMuted }}>Routes to:</span>
            {selRouting.map(r => (
              <span key={r.expertIdx} style={{ fontSize: 10, padding: '2px 8px', background: expertColors[r.expertIdx] + '20', border: '1px solid ' + expertColors[r.expertIdx] + '50', borderRadius: 4, color: expertColors[r.expertIdx] }}>
                E{r.expertIdx} ({(r.normWeight * 100).toFixed(0)}%)
              </span>
            ))}
          </div>
        </div>

        {/* Insight */}
        <div style={{ padding: '10px 14px', background: theme.colors.surfaceAlt, borderRadius: 8, fontSize: 11, color: theme.colors.textSecondary, lineHeight: 1.6, textAlign: 'center' }}>
          <strong style={{ color: theme.colors.text }}>Insight:</strong> {getInsight()}
        </div>
      </div>
    </div>
  );
}
